import React, { useState } from 'react'; // Importing useState
import { GenerationResult, SystemMode } from '../types';
import { Copy, Check, Sparkles, Command } from 'lucide-react';

interface ResultViewProps {
    result: GenerationResult;
}

interface PromptLineProps {
    line: string;
}

const PromptCopyButton: React.FC<{ prompt: string }> = ({ prompt }) => {
    const [copied, setCopied] = React.useState(false);

    const handleCopy = async () => {
        try {
            await navigator.clipboard.writeText(prompt);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000); // Reset after 2 seconds
        } catch (err) {
            console.error('Failed to copy text: ', err);
        }
    };

    return (
        <button
            onClick={handleCopy}
            className="absolute top-0 right-0 opacity-0 hover:opacity-100 transition-opacity bg-apple-off-white/10 p-1 rounded-sm"
        >
            {copied ? <Check size={16} /> : <Copy size={16} />}
        </button>
    );
};

const PromptLine: React.FC<PromptLineProps> = ({ line }) => {
    const isPromptLine = line.includes('**Prompt (English)**:');
    if (!isPromptLine) {
        return <>{line}</>;
    }

    const [label, prompt] = line.split(':').map((s) => s.replace(/\*+/g, '').trim());

    return (
        <div className="relative">
            <strong>{label}:</strong> {prompt}
            <PromptCopyButton prompt={prompt} />
        </div>
    );
};

export const ResultView: React.FC<ResultViewProps> = ({ result }) => {
    //  const [copied, setCopied] = React.useState(false); // Removed as it's now handled in PromptCopyButton

    if (!result) {
        return <div>Loading...</div>;
    }

    return (
        <div
            className="whitespace-pre-wrap font-mono text-xs md:text-sm leading-relaxed text-apple-text/80 font-medium"
        >
            {result.output.split('\n').map((line, index) => (
                <PromptLine key={index} line={line} />
            ))}
        </div>
    );
};
```


