import React, { useState, useCallback } from 'react';
import { GenerationResult, SystemMode } from '../types';
import { Copy, Check, Sparkles, Command } from 'lucide-react';
import { GlassCard } from './GlassCard';

interface ResultViewProps {
    result: GenerationResult | null;
}

const PromptLine: React.FC<{ line: string }> = ({ line }) => {
    const [copied, setCopied] = useState(false);

    // Robust parsing logic
    let label = "PROMPT";
    let content = line;

    const splitIndex = line.indexOf(':');
    if (splitIndex !== -1) {
        label = line.substring(0, splitIndex).replace(/\*/g, '').trim();
        content = line.substring(splitIndex + 1).trim();
    } else {
        const prefix = "**Prompt (English)**";
        if (line.includes(prefix)) {
            label = "Prompt (English)";
            content = line.replace(prefix, "").trim();
        }
    }

    // Clean up content slightly
    content = content.trim();

    const handleCopy = useCallback((e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();

        if (!content) return;

        const onCopySuccess = () => {
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        };

        // Fallback method using execCommand
        const fallbackCopy = () => {
            try {
                const textArea = document.createElement("textarea");
                textArea.value = content;

                // Ensure it's not visible but part of the layout
                textArea.style.position = "fixed";
                textArea.style.left = "-9999px";
                textArea.style.top = "0";
                textArea.setAttribute("readonly", "");

                document.body.appendChild(textArea);
                textArea.focus();
                textArea.select();

                const successful = document.execCommand('copy');
                document.body.removeChild(textArea);

                if (successful) {
                    onCopySuccess();
                } else {
                    console.error('Fallback copy failed');
                }
            } catch (err) {
                console.error('Fallback copy error', err);
            }
        };

        // Attempt Copy
        if (navigator.clipboard && navigator.clipboard.writeText) {
            navigator.clipboard.writeText(content)
                .then(onCopySuccess)
                .catch((err) => {
                    console.warn('Clipboard API failed, trying fallback', err);
                    fallbackCopy();
                });
        } else {
            fallbackCopy();
        }
    }, [content]);

    return (
        <div className="relative group my-3 p-4 bg-[#1c1c1e]/60 rounded-xl border border-white/10 hover:border-apple-blue/50 transition-all duration-300 shadow-sm">
            {/* Floating Copy Button - Positioned absolutely with high z-index */}
            <button 
                onClick={handleCopy}
                className={`
                    absolute top-3 right-3 z-50
                    flex items-center justify-center gap-1.5 
                    h-8 px-3
                    rounded-full backdrop-blur-md border shadow-lg cursor-pointer
                    transition-all duration-200 select-none
                    ${copied 
                        ? 'bg-green-500/20 border-green-500 text-green-400' 
                        : 'bg-white/10 border-white/20 text-white hover:bg-apple-blue hover:border-apple-blue'
                    }
                `}
                title="复制提示词"
                type="button"
            >
                {copied ? <Check size={14} strokeWidth={3} /> : <Copy size={14} />}
                <span className="text-xs font-bold">{copied ? '已复制' : '复制'}</span>
            </button>

            <div className="flex flex-col gap-2 relative z-10">
                {/* Label */}
                <div className="flex items-center">
                     <span className="text-[10px] font-bold uppercase tracking-wider text-apple-blue bg-apple-blue/10 px-2 py-0.5 rounded border border-apple-blue/20 select-none">
                        {label}
                    </span>
                </div>

                {/* Content - Selectable Text */}
                <div className="text-apple-text/90 font-mono text-sm leading-relaxed break-words whitespace-pre-wrap select-all pr-24">
                    {content}
                </div>
            </div>
        </div>
    );
};

